import { graphql, useStaticQuery } from 'gatsby';
import React, { useContext } from 'react';

import accreditationDocLink from '../../../static/docs/Аккредитация МинКомСвязь.pdf';
import privacyPolicyDocLink from '../../../static/docs/Политика_в_области_обработки_и_защиты_персональных_данных_0_5.pdf';
import { appContext } from '../../context/context';
import { useClassnames } from '../../hooks/use-classnames';
import { formatText, gtagClicked } from '../../utils';
import Button from '../button-like/button';
import GridWrapper from '../grid-wrapper';
import Heading from '../heading';
import Text from '../text';

import './index.css';

const DEFAULT_FOOTER_CONTENT = {
    modalLinkText      : 'Связаться с нами',
    copyright          : '© SberAutoTech, 2022',
    coreBusiness       : 'Основной вид деятельности: ОКВЭД 62.01',
    accreditationText  : 'Аккредитация в качестве ИТ-компании',
    accreditationIsLink: true,
    privacyPolicyIsLink: true
};

const query = graphql`
  query {
    allStrapiFooter {
      edges {
        node {
          header
          disclaimer
          privacyPolicyText
        }
      }
    },
  }
`;

interface IProps {
    header?: string,
    className?: string
}

const Footer = ({ className, header: headerFromProps }: IProps) => {
    const cn = useClassnames();
    const data = useStaticQuery(query);
    const { setIsContactFormVisible } = useContext(appContext);
    const { header, disclaimer, privacyPolicyText } = data.allStrapiFooter.edges[0].node;
    const {
        modalLinkText,
        copyright,
        coreBusiness,
        accreditationText,
        accreditationIsLink,
        privacyPolicyIsLink
    } = DEFAULT_FOOTER_CONTENT;

    const handleClick = () => {
        gtagClicked('footer_button_click');
        setIsContactFormVisible?.(true);
    };

    return (
        <GridWrapper as="footer" className={cn('main-footer', className)}>
            <Heading className={cn('main-footer__header')} level={2} dangerouslySetInnerHTML={{ __html: formatText(headerFromProps || header) }} />

            <Button
                className={cn('main-footer__button')}
                buttonSize="s"
                onClick={handleClick}
            >
                {modalLinkText}
            </Button>

            <Text
                className={cn('main-footer__disclaimer')}
                as="p"
                size={5}
                dangerouslySetInnerHTML={{ __html: disclaimer }}
            />

            <Text className={cn('main-footer__copyright')} as="span" size={5}>{copyright}</Text>

            <Text className={cn('main-footer__legal-info')} size={5}>
                <span className={cn('main-footer__core-business')}>
                    {coreBusiness}
                </span>

                {
                    accreditationText && (
                        accreditationIsLink
                            ? (
                                <a
                                    className={cn('main-footer__accreditation')}
                                    href={accreditationDocLink}
                                    target="_blank"
                                    rel="noopener noreferrer"
                                >
                                    {accreditationText}
                                </a>
                            )

                            : <span className={cn('main-footer__accreditation')}>{accreditationText}</span>
                    )
                }

                {
                    privacyPolicyText && (
                        privacyPolicyIsLink
                            ? (
                                <a
                                    className={cn('main-footer__privacy-policy')}
                                    href={privacyPolicyDocLink}
                                    target="_blank"
                                    rel="noopener noreferrer"
                                >
                                    {privacyPolicyText}
                                </a>
                            )
                            : <span className={cn('main-footer__privacy-policy')}>{privacyPolicyText}</span>
                    )
                }
            </Text>

        </GridWrapper>
    );
};

export default Footer;
